import{addMediaTypePlugin}from"./media-types.js";const is31=RegExp.prototype.test.bind(/^3\.1\.\d+(-.+)?$/),is30=RegExp.prototype.test.bind(/^3\.0\.\d+(-.+)?$/);addMediaTypePlugin("application/openapi+json",{parse:async(e,s)=>{var o=await e.json();let p;s=o.openapi||s.version;if(!s)throw Error("Invalid OpenAPI document. Add the 'openapi' field and try again.");if(is30(s))p="https://spec.openapis.org/oas/3.0/schema";else{if(!is31(s))throw Error(`Encountered unsupported OpenAPI version '${s}' in `+e.url);p="jsonSchemaDialect"in o&&"https://spec.openapis.org/oas/3.1/dialect/base"!==o.jsonSchemaDialect?"https://spec.openapis.org/oas/3.1/schema-"+encodeURIComponent(o.jsonSchemaDialect):"https://spec.openapis.org/oas/3.1/schema-base"}return[o,p]},matcher:e=>/(\/|\.)openapi\.json$/.test(e)});